fn test1() {
    let x: [u8; 6] = [11, 12, 13, 14, 15, 16];
    assert(x.view().len() == 6);
    assert(x.view()[0] == 11);
    assert(x.view()[1] == 12);
    assert(x.view()[2] == 13);
    assert(x.view()[3] == 14);
    assert(x.view()[4] == 15);
    assert(x.view()[5] == 16);
}

fn test2<T>(a: T, b: T, c: T) {
    let x: [T; 3] = [a, b, c];
    assert(x.view().len() == 3);
    assert(x.view()[0] == a);
    assert(x.view()[1] == b);
    assert(x.view()[2] == c);
}

fn test3() {
    let x: [u8; 6] = [11, 12, 13, 14, 15, 16];
    assert(x.view().len() == 6);
    assert(x.view()[0] == 12); // FAILS
}

fn test4() {
    let a1: [u8; 3] = [10, 20, 30];
    let a2: [u8; 3] = [10, 20, 40];
    assert(a1 != a2);
    assert(a1@ != a2@);
    assert(a1@.contains(30));
    assert(a2@.contains(30)); // FAILS
}

proof fn test5() {
    let s1: Seq<int> = [10, 20, 30]@;
    let s2: Seq<int> = [10, 20, 40]@;
    assert(s1 != s2);
    assert(s1 == s2); // FAILS
}

proof fn test6() {
    let s: Seq<int> = [10, 20, 30]@;
    assert(s.contains(30));
    assert(s.contains(40)); // FAILS
}

fn test2<T>(a: T, b: T) {
    let x: [T; 3] = [a, b, b];
}

fn test1() {
    let x: [u8; 6] = [11; 6];
    assert(x.view().len() == 6);
    assert(x.view()[0] == 11);
    assert(x.view()[1] == 11);
    assert(x.view()[2] == 11);
    assert(x.view()[3] == 11);
    assert(x.view()[4] == 11);
    assert(x.view()[5] == 11);
}

fn test2<T: Copy>(a: T) {
    let x: [T; 3] = [a; 3];
    assert(x.view().len() == 3);
    assert(x.view()[0] == a);
    assert(x.view()[1] == a);
    assert(x.view()[2] == a);
}

fn test3<T: Copy, const N: usize>(a: T, i: usize) {
    let x: [T; N] = [a; N];
    assert(x.view().len() == N);

    assume(0 <= i < N);
    assert(x.view()[i as int] == a);
}

proof fn test4<T: Copy, const N: usize>(a: T, i: usize) {
    let x: [T; N] = [a; N];
    assert(x.view().len() == N);

    assume(0 <= i < N);
    assert(x.view()[i as int] == a);
}

fn test5() {
    let x: [u8; 6] = [11; 6];
    assert(x.view().len() == 7); // FAILS
}

