    let b2 = (b & 0x0000_0000_ffff_ffffu64) as u32;
    assert(b == add(mul(b1 as u64, 0x100000000), b2 as u64)) by(bit_vector)
        requires
            b1 == (b >> 32u64) as u32,
            b2 == (b & 0x0000_0000_ffff_ffffu64) as u32;
    (b1, b2)
}

