    spec fn spec_get_x() -> u64;

    proof fn proof_get_x(t: u64, u: u64)
        requires t == X,
        ensures u == X;

    fn exec_get_x(&self) -> (r: u64)
        ensures r == X;
}

struct Foo<const X: u64> {
}

impl<const X: u64> Trait<X> for Foo<X> {
    open spec fn spec_get_x() -> u64 {
        X
    }

    proof fn proof_get_x(t: u64, u: u64) {
        assert(t == X);
        assert(u == X); // FAILS
