// test generics

fn test_generic<const X: u64, T: Trait<X>>(r: T) {
    let y = r.exec_get_x();
    assert(y == X);

    proof {
        let j = T::spec_get_x();
        T::proof_get_x(X, 8);
    }
    assert(X == 8);
}

fn test_generic_fail<const X: u64, T: Trait<X>>(r: T) {
    proof {
        T::proof_get_x(5, 8); // FAILS
    }
}

