fn test_specific<const X: u64>(r: Foo<X>) {
    let y = r.exec_get_x();
    assert(y == X);

    proof {
        let j = Foo::<X>::spec_get_x();
        assert(j == X);
        Foo::<X>::proof_get_x(X, 8);
    }
    assert(X == 8);
}

