impl T for u16 {
    spec fn b(&self) -> u8 { (*self / 256) as u8 }
    fn f(&self) -> (r: u8) { (*self / 512) as u8 }
}
impl T for u32 {
    fn f(&self) -> (r: u8) { 4 }
}
fn test_coerce() {
    let u: u8 = 7;
    let d: &dyn T = &u; // ToDyn coercion
    let r = d.f();
    assert(d.b() == 7);
    assert(r <= 10);

    let x: u32 = 9;
    let d: Box<dyn T> = Box::new(x); // ToDyn coercion
    let r = d.f();
    assert(d.b() == 5);
    assert(r <= 10);

    let y: u16 = 8;
    let d: Box<dyn T> = Box::new(y); // ToDyn coercion
    let r = d.f();
    assert(d.b() == 5); // FAILS
}

